import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { FaHome, FaBars, FaSearch, FaCog } from 'react-icons/fa';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  const navItems = [
    { path: '/menu', label: 'MENU', icon: FaBars },
    { path: '/search', label: 'SEARCH', icon: FaSearch },
    { path: '/', label: 'HOME', icon: FaHome },
    { path: '/settings', label: 'SETTINGS', icon: FaCog }
  ];

  return (
    <nav 
      className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 shadow-lg z-50"
      role="navigation"
      aria-label="Main navigation"
    >
      <div className="flex justify-around items-center h-20 px-4">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          
          return (
            <Link
              key={item.path}
              to={item.path}
              className="flex flex-col items-center justify-center py-2 px-3 transition-all duration-200 no-underline focus-ring"
              style={{ textDecoration: 'none' }}
              aria-label={`Navigate to ${item.label}`}
            >
              <div className="flex items-center justify-center w-12 h-12 mb-1">
                <Icon className={`text-2xl transition-colors duration-200 ${
                  isActive 
                    ? 'text-gray-800' 
                    : 'text-gray-600 hover:text-gray-800'
                }`} />
              </div>
              <span className={`text-xs font-medium uppercase tracking-wide ${
                isActive 
                  ? 'text-gray-800' 
                  : 'text-gray-600'
              }`}>
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
